// For submission: write both classes in one file using a static nested approach
public class PackageDemo {
    static class Greeter {
        public static String greet(String name) {
            return "Hello, " + name + "! Welcome to Java packages.";
        }
    }

    public static void main(String[] args) {
        System.out.println(Greeter.greet("Learner"));
        System.out.println(Greeter.greet("Java Dev"));
    }
}
